import{f as i,D as E,o as s,c as p,a2 as r,b as d,w as a,a as e,G as l,a5 as o}from"./chunks/framework.Ccw_j35p.js";const m=JSON.parse('{"title":"微服务架构全景","description":"","frontmatter":{},"headers":[],"relativePath":"spring-ecosystem/microservice-methodology/index.md","filePath":"spring-ecosystem/microservice-methodology/index.md","lastUpdated":1780925101000}'),A={name:"spring-ecosystem/microservice-methodology/index.md"};function h(b,t,g,c,B,u){const n=E("Mermaid");return s(),p("div",null,[t[3]||(t[3]=r('<h1 id="微服务架构全景" tabindex="-1">微服务架构全景 <a class="header-anchor" href="#微服务架构全景" aria-label="Permalink to &quot;微服务架构全景&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识模块</th><th>重点内容</th><th>面试频率</th></tr></thead><tbody><tr><td>架构演进路径</td><td>单体 → SOA → 微服务，每个阶段的痛点和驱动力</td><td>极高</td></tr><tr><td>微服务核心特征</td><td>独立部署、去中心化治理、围绕业务组织、数据隔离</td><td>极高</td></tr><tr><td>优点与代价</td><td>敏捷性、可扩展性、技术异构 vs 分布式复杂度、运维成本</td><td>极高</td></tr><tr><td>适用场景判断</td><td>业务复杂度、团队规模、交付速度要求、技术储备四维评估</td><td>高</td></tr><tr><td>何时不用微服务</td><td>初创项目、简单 CRUD、团队能力不足、基础设施不健全</td><td>高</td></tr><tr><td>常见反模式</td><td>分布式单体、数据大杂烩、粒度不当、技术栈碎片化</td><td>中高</td></tr><tr><td>微服务成熟度模型</td><td>从入门到深水区的演进路线图</td><td>中</td></tr></tbody></table><hr><h2 id="一、架构演进-从单体到微服务" tabindex="-1">一、架构演进：从单体到微服务 <a class="header-anchor" href="#一、架构演进-从单体到微服务" aria-label="Permalink to &quot;一、架构演进：从单体到微服务&quot;">​</a></h2><h3 id="_1-1-演进历程全景" tabindex="-1">1.1 演进历程全景 <a class="header-anchor" href="#_1-1-演进历程全景" aria-label="Permalink to &quot;1.1 演进历程全景&quot;">​</a></h3>',6)),(s(),d(o,null,{default:a(()=>[l(n,{id:"mermaid-107",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%E9%98%B6%E6%AE%B5%E4%B8%80%0A%20%20%20%20%20%20%20%20A%5B%E5%8D%95%E4%BD%93%E6%9E%B6%E6%9E%84%3Cbr%2F%3EMonolith%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E9%98%B6%E6%AE%B5%E4%BA%8C%0A%20%20%20%20%20%20%20%20B%5BSOA%3Cbr%2F%3E%E9%9D%A2%E5%90%91%E6%9C%8D%E5%8A%A1%E6%9E%B6%E6%9E%84%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E9%98%B6%E6%AE%B5%E4%B8%89%0A%20%20%20%20%20%20%20%20C%5B%E5%BE%AE%E6%9C%8D%E5%8A%A1%3Cbr%2F%3EMicroservices%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%BD%93%E5%89%8D%E6%BC%94%E8%BF%9B%0A%20%20%20%20%20%20%20%20D%5BService%20Mesh%3Cbr%2F%3E%E6%9C%8D%E5%8A%A1%E7%BD%91%E6%A0%BC%5D%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20A%20--%3E%7C%22%E4%B8%9A%E5%8A%A1%E8%86%A8%E8%83%80%3Cbr%2F%3E%E4%BB%A3%E7%A0%81%E8%80%A6%E5%90%88%E4%B8%A5%E9%87%8D%22%7C%20B%0A%20%20%20%20B%20--%3E%7C%22ESB%20%E8%BF%87%E9%87%8D%3Cbr%2F%3E%E6%B2%BB%E7%90%86%E5%A4%8D%E6%9D%82%22%7C%20C%0A%20%20%20%20C%20--%3E%7C%22%E9%80%9A%E4%BF%A1%E6%B2%BB%E7%90%86%E4%B8%8B%E6%B2%89%3Cbr%2F%3E%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%22%7C%20D%0A%20%20%20%20%0A%20%20%20%20style%20A%20fill%3A%23ff6b6b%2Ccolor%3A%23fff%0A%20%20%20%20style%20B%20fill%3A%23ffd93d%2Ccolor%3A%23333%0A%20%20%20%20style%20C%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20D%20fill%3A%234d96ff%2Ccolor%3A%23fff%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[e(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r(`<h3 id="_1-2-单体架构阶段" tabindex="-1">1.2 单体架构阶段 <a class="header-anchor" href="#_1-2-单体架构阶段" aria-label="Permalink to &quot;1.2 单体架构阶段&quot;">​</a></h3><p><strong>特征</strong>：所有功能模块打包在一个应用进程中，共享同一个数据库。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│          单体应用 (WAR/JAR)              │</span></span>
<span class="line"><span>│  ┌──────┐ ┌──────┐ ┌──────┐ ┌──────┐  │</span></span>
<span class="line"><span>│  │ 订单  │ │ 用户  │ │ 商品  │ │ 支付  │  │</span></span>
<span class="line"><span>│  │Module│ │Module│ │Module│ │Module│  │</span></span>
<span class="line"><span>│  └──────┘ └──────┘ └──────┘ └──────┘  │</span></span>
<span class="line"><span>│           ┌────────────────┐           │</span></span>
<span class="line"><span>│           │   共享数据库     │           │</span></span>
<span class="line"><span>│           └────────────────┘           │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">单体架构并非一无是处</p><p>单体架构在项目初期具有开发效率高、部署简单、调试方便的优势。许多成功的项目都是从单体起步的。问题在于<strong>业务膨胀到一定程度后</strong>，单体架构的弊端开始显现。</p></div><p><strong>单体的痛点</strong>：</p><table tabindex="0"><thead><tr><th>痛点</th><th>表现</th></tr></thead><tbody><tr><td>代码耦合</td><td>修改订单模块可能影响用户模块，牵一发而动全身</td></tr><tr><td>部署瓶颈</td><td>改一行代码需要全量构建和部署，CI/CD 时间越来越长</td></tr><tr><td>扩展困难</td><td>不能按模块独立扩缩容，商品模块的流量高峰需要整体扩容</td></tr><tr><td>技术锁定</td><td>全项目绑定同一技术栈，难以针对不同场景选择最优工具</td></tr><tr><td>团队协作</td><td>多人修改同一代码库，合并冲突频繁，迭代速度下降</td></tr></tbody></table><h3 id="_1-3-soa-阶段" tabindex="-1">1.3 SOA 阶段 <a class="header-anchor" href="#_1-3-soa-阶段" aria-label="Permalink to &quot;1.3 SOA 阶段&quot;">​</a></h3><p>SOA（Service-Oriented Architecture）尝试通过 ESB（企业服务总线）将系统拆分为独立服务。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    ESB（企业服务总线）                       │</span></span>
<span class="line"><span>│          ┌─────────────────────────────────┐             │</span></span>
<span class="line"><span>│          │  消息路由 / 协议转换 / 数据格式转换  │             │</span></span>
<span class="line"><span>│          └─────────────────────────────────┘             │</span></span>
<span class="line"><span>│        ↙       ↓        ↓        ↓        ↘              │</span></span>
<span class="line"><span>│  ┌────────┐┌────────┐┌────────┐┌────────┐┌────────┐    │</span></span>
<span class="line"><span>│  │订单服务││用户服务││商品服务││支付服务││库存服务│    │</span></span>
<span class="line"><span>│  └────────┘└────────┘└────────┘└────────┘└────────┘    │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">SOA 的致命缺陷</p><p>ESB 成为整个系统的<strong>单点瓶颈</strong>和<strong>治理黑洞</strong>。所有服务间通信都经过 ESB，ESB 挂了全系统瘫痪。此外，SOA 强调组织级的服务复用，往往导致服务粒度太粗。SOA 的重型协议（SOAP/WS-*）也是开发者的一大痛点。</p></div><h3 id="_1-4-微服务架构" tabindex="-1">1.4 微服务架构 <a class="header-anchor" href="#_1-4-微服务架构" aria-label="Permalink to &quot;1.4 微服务架构&quot;">​</a></h3><p>微服务继承了 SOA 的服务化思想，但摒弃了重型 ESB，采用<strong>轻量级通信</strong>（HTTP/REST、gRPC）和<strong>去中心化治理</strong>。</p>`,12)),(s(),d(o,null,{default:a(()=>[l(n,{id:"mermaid-195",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%E6%8E%A5%E5%85%A5%E5%B1%82%0A%20%20%20%20%20%20%20%20GW%5BAPI%20%E7%BD%91%E5%85%B3%3Cbr%2F%3E%E7%BB%9F%E4%B8%80%E5%85%A5%E5%8F%A3%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E4%B8%9A%E5%8A%A1%E6%9C%8D%E5%8A%A1%E5%B1%82%0A%20%20%20%20%20%20%20%20S1%5B%E8%AE%A2%E5%8D%95%E6%9C%8D%E5%8A%A1%3Cbr%2F%3EOrder%20DB%5D%0A%20%20%20%20%20%20%20%20S2%5B%E7%94%A8%E6%88%B7%E6%9C%8D%E5%8A%A1%3Cbr%2F%3EUser%20DB%5D%0A%20%20%20%20%20%20%20%20S3%5B%E5%95%86%E5%93%81%E6%9C%8D%E5%8A%A1%3Cbr%2F%3EProduct%20DB%5D%0A%20%20%20%20%20%20%20%20S4%5B%E6%94%AF%E4%BB%98%E6%9C%8D%E5%8A%A1%3Cbr%2F%3EPayment%20DB%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%E5%B1%82%0A%20%20%20%20%20%20%20%20REG%5B%E6%B3%A8%E5%86%8C%E4%B8%AD%E5%BF%83%3Cbr%2F%3ENacos%2FEureka%5D%0A%20%20%20%20%20%20%20%20CFG%5B%E9%85%8D%E7%BD%AE%E4%B8%AD%E5%BF%83%3Cbr%2F%3ENacos%20Config%5D%0A%20%20%20%20%20%20%20%20TRACE%5B%E9%93%BE%E8%B7%AF%E8%BF%BD%E8%B8%AA%3Cbr%2F%3ESkyWalking%5D%0A%20%20%20%20%20%20%20%20MONITOR%5B%E7%9B%91%E6%8E%A7%E5%91%8A%E8%AD%A6%3Cbr%2F%3EPrometheus%5D%0A%20%20%20%20end%0A%0A%20%20%20%20GW%20--%3E%20S1%0A%20%20%20%20GW%20--%3E%20S2%0A%20%20%20%20GW%20--%3E%20S3%0A%20%20%20%20GW%20--%3E%20S4%0A%20%20%20%20S1%20-.-%3E%20REG%0A%20%20%20%20S2%20-.-%3E%20REG%0A%20%20%20%20S3%20-.-%3E%20REG%0A%20%20%20%20S4%20-.-%3E%20REG%0A%20%20%20%20S1%20-.-%3E%20CFG%0A%20%20%20%20S1%20-.-%3E%20TRACE%0A%20%20%20%20S1%20-.-%3E%20MONITOR%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[e(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=r('<hr><h2 id="二、微服务的核心特征" tabindex="-1">二、微服务的核心特征 <a class="header-anchor" href="#二、微服务的核心特征" aria-label="Permalink to &quot;二、微服务的核心特征&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特征</th><th>说明</th></tr></thead><tbody><tr><td><strong>组件化，而非库化</strong></td><td>服务是独立可部署的组件，而非代码层面的库</td></tr><tr><td><strong>围绕业务能力组织</strong></td><td>康威定律：系统架构反映组织沟通结构</td></tr><tr><td><strong>产品而非项目</strong></td><td>团队对服务的全生命周期负责（你构建，你运维）</td></tr><tr><td><strong>智能端点，哑管道</strong></td><td>服务本身有完整的业务逻辑，通信管道只负责传输</td></tr><tr><td><strong>去中心化治理</strong></td><td>每个服务可以选择最适合的技术栈</td></tr><tr><td><strong>去中心化数据管理</strong></td><td>每个服务拥有自己的数据库，数据隔离</td></tr><tr><td><strong>基础设施自动化</strong></td><td>CI/CD、自动化测试、容器化部署是微服务的先决条件</td></tr><tr><td><strong>容错设计</strong></td><td>拥抱失败，假设服务随时可能出问题</td></tr><tr><td><strong>演进式设计</strong></td><td>服务可以被独立替换或废弃</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">微服务不是银弹</p><p>微服务解决的<strong>是组织架构和团队协作的问题</strong>，而非技术问题。如果你的团队只有 5 个人，引入微服务会<strong>增加</strong>而非减少你的工作量。微服务本质上是用<strong>运维复杂度换取开发敏捷性</strong>的权衡。</p></div><hr><h2 id="三、何时使用微服务" tabindex="-1">三、何时使用微服务？ <a class="header-anchor" href="#三、何时使用微服务" aria-label="Permalink to &quot;三、何时使用微服务？&quot;">​</a></h2><h3 id="_3-1-适用场景-四维评估模型" tabindex="-1">3.1 适用场景（四维评估模型） <a class="header-anchor" href="#_3-1-适用场景-四维评估模型" aria-label="Permalink to &quot;3.1 适用场景（四维评估模型）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>评估维度</th><th>适合微服务</th><th>不适合微服务</th></tr></thead><tbody><tr><td><strong>业务复杂度</strong></td><td>多业务领域，逻辑差异大</td><td>简单 CRUD，业务变化少</td></tr><tr><td><strong>团队规模</strong></td><td>多团队（&gt;20 人）并行开发</td><td>小团队（&lt;10 人）</td></tr><tr><td><strong>交付速度</strong></td><td>需要独立迭代、快速试错</td><td>发布周期长，无快速迭代诉求</td></tr><tr><td><strong>技术储备</strong></td><td>具备 DevOps、容器化、监控能力</td><td>缺乏基础设施和运维能力</td></tr></tbody></table><h3 id="_3-2-明确不建议用微服务的场景" tabindex="-1">3.2 明确不建议用微服务的场景 <a class="header-anchor" href="#_3-2-明确不建议用微服务的场景" aria-label="Permalink to &quot;3.2 明确不建议用微服务的场景&quot;">​</a></h3><ol><li><strong>项目处于 0→1 阶段</strong>：需求不确定，架构在快速演化，此时微服务的高成本会拖慢验证速度</li><li><strong>简单的内部管理系统</strong>：数十张表的 CRUD 系统，单体 + 水平扩展足够</li><li><strong>强事务一致性场景</strong>：跨服务分布式事务是微服务最大的痛点之一，如果业务强依赖 ACID，三思</li><li><strong>团队缺乏 DevOps 能力</strong>：没有自动化 CI/CD、容器化、监控体系的团队做微服务等于灾难</li><li><strong>性能极度敏感场景</strong>：服务间网络调用带来的延迟在部分金融交易场景中不可接受</li></ol><h3 id="_3-3-演进策略-绞杀者模式" tabindex="-1">3.3 演进策略：绞杀者模式 <a class="header-anchor" href="#_3-3-演进策略-绞杀者模式" aria-label="Permalink to &quot;3.3 演进策略：绞杀者模式&quot;">​</a></h3><p>逐步从单体中剥离功能，而非一次性大爆炸式重写：</p>',12)),(s(),d(o,null,{default:a(()=>[l(n,{id:"mermaid-395",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E5%8D%95%E4%BD%93%E5%BA%94%E7%94%A8%5D%20--%3E%7C%22%E9%98%B6%E6%AE%B5%E4%B8%80%3Cbr%2F%3E%E5%89%A5%E7%A6%BB%E8%BE%B9%E7%BC%98%E6%A8%A1%E5%9D%97%22%7C%20B%5B%E5%8D%95%E4%BD%93%20%2B%20%E5%B0%91%E9%87%8F%E5%BE%AE%E6%9C%8D%E5%8A%A1%5D%0A%20%20%20%20B%20--%3E%7C%22%E9%98%B6%E6%AE%B5%E4%BA%8C%3Cbr%2F%3E%E5%89%A5%E7%A6%BB%E6%A0%B8%E5%BF%83%E6%A8%A1%E5%9D%97%22%7C%20C%5B%E5%BE%AE%E6%9C%8D%E5%8A%A1%E4%B8%BA%E4%B8%BB%20%2B%20%E9%81%97%E7%95%99%E5%8D%95%E4%BD%93%5D%0A%20%20%20%20C%20--%3E%7C%22%E9%98%B6%E6%AE%B5%E4%B8%89%3Cbr%2F%3E%E5%AE%8C%E5%85%A8%E8%BF%81%E7%A7%BB%22%7C%20D%5B%E7%BA%AF%E5%BE%AE%E6%9C%8D%E5%8A%A1%E6%9E%B6%E6%9E%84%5D%0A%20%20%20%20%0A%20%20%20%20style%20A%20fill%3A%23ff6b6b%2Ccolor%3A%23fff%0A%20%20%20%20style%20B%20fill%3A%23ffd93d%2Ccolor%3A%23333%0A%20%20%20%20style%20C%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20D%20fill%3A%234d96ff%2Ccolor%3A%23fff%0A"})]),fallback:a(()=>[...t[2]||(t[2]=[e(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=r('<hr><h2 id="四、微服务的代价与挑战" tabindex="-1">四、微服务的代价与挑战 <a class="header-anchor" href="#四、微服务的代价与挑战" aria-label="Permalink to &quot;四、微服务的代价与挑战&quot;">​</a></h2><table tabindex="0"><thead><tr><th>挑战</th><th>详情</th></tr></thead><tbody><tr><td><strong>分布式复杂度</strong></td><td>网络不可靠、延迟、分布式事务、数据一致性</td></tr><tr><td><strong>运维成本</strong></td><td>需要容器编排（K8s）、CI/CD 流水线、统一监控</td></tr><tr><td><strong>调试难度</strong></td><td>一个请求跨越多个服务，需链路追踪定位问题</td></tr><tr><td><strong>数据一致性</strong></td><td>放弃 ACID，拥抱最终一致性，需要补偿机制</td></tr><tr><td><strong>服务间通信</strong></td><td>网络开销、序列化/反序列化、超时重试策略</td></tr><tr><td><strong>测试复杂度</strong></td><td>需要契约测试、端到端测试、Mock 多服务依赖</td></tr><tr><td><strong>版本兼容</strong></td><td>多服务独立演进带来的 API 版本管理问题</td></tr></tbody></table><hr><h2 id="五、微服务成熟度模型" tabindex="-1">五、微服务成熟度模型 <a class="header-anchor" href="#五、微服务成熟度模型" aria-label="Permalink to &quot;五、微服务成熟度模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>等级</th><th>特征</th><th>关键能力</th></tr></thead><tbody><tr><td><strong>L1：起步</strong></td><td>简单拆分，手工部署</td><td>服务拆分原则、API 定义</td></tr><tr><td><strong>L2：标准化</strong></td><td>统一框架，自动化构建</td><td>CI/CD、容器化、注册发现</td></tr><tr><td><strong>L3：可观测</strong></td><td>全链路监控、日志聚合</td><td>链路追踪、指标监控、告警</td></tr><tr><td><strong>L4：自愈</strong></td><td>熔断降级、自动扩缩容</td><td>限流、熔断、弹性伸缩</td></tr><tr><td><strong>L5：服务网格</strong></td><td>通信下沉 Sidecar，业务零侵入</td><td>Service Mesh、可观测性标准化</td></tr></tbody></table><hr><h2 id="⭐-面试高频问题汇总" tabindex="-1">⭐ 面试高频问题汇总 <a class="header-anchor" href="#⭐-面试高频问题汇总" aria-label="Permalink to &quot;⭐ 面试高频问题汇总&quot;">​</a></h2><h3 id="q1-单体架构-vs-微服务架构的核心区别是什么" tabindex="-1">Q1：单体架构 vs 微服务架构的核心区别是什么？ <a class="header-anchor" href="#q1-单体架构-vs-微服务架构的核心区别是什么" aria-label="Permalink to &quot;Q1：单体架构 vs 微服务架构的核心区别是什么？&quot;">​</a></h3><p>核心区别在于<strong>部署单元</strong>和<strong>数据管理</strong>：</p><ul><li><strong>单体</strong>：所有功能打包在同一进程，共享数据库；部署一次更新全部；扩展只能整体扩展</li><li><strong>微服务</strong>：每个服务独立进程、独立数据库、独立部署、独立扩缩容</li></ul><p>这不是技术优劣之分，而是<strong>业务复杂度达到一定阈值后的自然选择</strong>。单体架构适合不确定性高、变化快的早期项目；微服务适合业务稳定、多团队并行的大型系统。</p><h3 id="q2-什么是-分布式单体-如何避免" tabindex="-1">Q2：什么是&quot;分布式单体&quot;？如何避免？ <a class="header-anchor" href="#q2-什么是-分布式单体-如何避免" aria-label="Permalink to &quot;Q2：什么是&quot;分布式单体&quot;？如何避免？&quot;">​</a></h3><p><strong>分布式单体</strong>是指：虽然系统在物理上拆分成了多个微服务，但逻辑上仍然高度耦合——服务之间必须同步调用、必须同时部署、必须共享数据库。</p><p><strong>避免策略</strong>：</p><ol><li>服务拥有自己的数据库，禁止跨服务直接访问数据库</li><li>使用异步消息解耦服务间依赖（事件驱动架构）</li><li>定义清晰的 API 契约，允许向后兼容的独立演进</li><li>每个服务可以独立部署，不要求&quot;全量同步上线&quot;</li></ol><h3 id="q3-微服务架构中最难解决的三个问题是什么" tabindex="-1">Q3：微服务架构中最难解决的三个问题是什么？ <a class="header-anchor" href="#q3-微服务架构中最难解决的三个问题是什么" aria-label="Permalink to &quot;Q3：微服务架构中最难解决的三个问题是什么？&quot;">​</a></h3><ol><li><p><strong>分布式数据一致性</strong>：跨服务事务无法使用单体数据库的 ACID 事务，必须依赖 Saga、TCC 等最终一致性方案。这是微服务最根本的挑战。</p></li><li><p><strong>服务间通信的可靠性</strong>：网络是不可靠的，需要有超时、重试、熔断、降级等完整的容错机制。一个服务挂了不能导致雪崩。</p></li><li><p><strong>可观测性</strong>：一个请求可能跨越 10+ 个服务，没有统一的链路追踪、日志聚合和指标监控，问题定位如同大海捞针。</p></li></ol><h3 id="q4-soa-和微服务有什么区别" tabindex="-1">Q4：SOA 和微服务有什么区别？ <a class="header-anchor" href="#q4-soa-和微服务有什么区别" aria-label="Permalink to &quot;Q4：SOA 和微服务有什么区别？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>SOA</th><th>微服务</th></tr></thead><tbody><tr><td>通信方式</td><td>重型 SOAP/WS-*，通过 ESB</td><td>轻量级 HTTP/REST、gRPC</td></tr><tr><td>数据管理</td><td>通常共享数据库</td><td>每个服务独立数据库</td></tr><tr><td>服务粒度</td><td>较粗，面向企业级复用</td><td>较细，面向单一职责</td></tr><tr><td>治理方式</td><td>集中式 ESB 治理</td><td>去中心化治理</td></tr><tr><td>技术栈</td><td>通常统一技术栈</td><td>允许多语言、多框架</td></tr><tr><td>部署</td><td>经常一起部署</td><td>独立部署</td></tr></tbody></table><p>SOA 的 ESB 是最大的问题——它变成了瓶颈和单点。微服务则选择&quot;智能端点、哑管道&quot;。</p><h3 id="q5-公司有一个运行-5-年的单体应用-业务增长快、部署频率越来越高、合并冲突严重。你会如何推动微服务化改造" tabindex="-1">Q5：公司有一个运行 5 年的单体应用，业务增长快、部署频率越来越高、合并冲突严重。你会如何推动微服务化改造？ <a class="header-anchor" href="#q5-公司有一个运行-5-年的单体应用-业务增长快、部署频率越来越高、合并冲突严重。你会如何推动微服务化改造" aria-label="Permalink to &quot;Q5：公司有一个运行 5 年的单体应用，业务增长快、部署频率越来越高、合并冲突严重。你会如何推动微服务化改造？&quot;">​</a></h3><p>采用**绞杀者模式（Strangler Fig Pattern）**逐步迁移：</p><ol><li><strong>评估阶段</strong>：识别单体中的模块边界，确定迁移优先级（边缘模块先行，核心模块最后）</li><li><strong>基础设施准备</strong>：搭建 CI/CD、容器化平台、注册中心、配置中心、监控体系 —— 这一步必须在代码迁移前完成</li><li><strong>剥离边缘模块</strong>：选择对核心流程依赖最少的模块（如消息通知、报表），用 API 网关将流量切换到新服务</li><li><strong>逐步剥离核心模块</strong>：按业务领域逐个迁移，新功能直接在新服务开发</li><li><strong>下线旧代码</strong>：当流量全部切换后，删除单体中的旧代码</li></ol><p>关键原则：<strong>渐进式迁移，每一步都可回退</strong>。不要一次性重写，那是灾难。</p><h3 id="q6-什么信号意味着你的系统需要从单体演进到微服务" tabindex="-1">Q6：什么信号意味着你的系统需要从单体演进到微服务？ <a class="header-anchor" href="#q6-什么信号意味着你的系统需要从单体演进到微服务" aria-label="Permalink to &quot;Q6：什么信号意味着你的系统需要从单体演进到微服务？&quot;">​</a></h3><ol><li><strong>团队协作瓶颈</strong>：多个团队修改同一代码库，合并冲突已成为日常</li><li><strong>部署耦合</strong>：改一行文案需要全量回归测试 + 全量部署</li><li><strong>扩展不均</strong>：不同模块的流量差异巨大，但只能整体扩缩容</li><li><strong>技术债累积</strong>：不同模块对技术栈的需求已经分化，但受限于统一技术栈</li><li><strong>故障爆炸半径大</strong>：一个非核心模块的内存泄漏导致整个系统瘫痪</li></ol><hr><div class="info custom-block"><p class="custom-block-title">相关模块</p><ul><li><a href="./../spring-cloud/">Spring Cloud 技术实现</a> — Nacos、Gateway、Sentinel、Seata 等</li><li>分布式理论（middleware/distributed-system/） — CAP、BASE、一致性协议</li><li>高并发架构（high-concurrency/） — 限流、降级、熔断策略</li><li>监控告警（high-concurrency/monitoring-alerting/） — Prometheus + Grafana 体系</li></ul></div>',29))])}const D=i(A,[["render",h]]);export{m as __pageData,D as default};
